head.script:
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "OP228", compID: "acb_ioClsCd,gr_InOutStockInfo:ioClsCd" } //구분
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_SetGridColumnMaxLength(gr_InOutStockInfo); // 그리드 maxlength 설정
};

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        //소스
        var dateStr = $c.date.getServerDateTime("yyyyMMdd"); //현재일자
        ica_outDt.setValue(dateStr);
        ed_inDtFrom.setValue(dateStr.substring(0, 6) + '01');
        ed_inDtTo.setValue(dateStr);

        $c.gus.cfDisableObjects([btn_addRow, btn_undoRow, btn_insert, btn_cancel, btn_pop, btn_delete, btn_save]);

        ed_clntNo.setValue("253811");
        scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'T', 'T');

        //테스트 데이터
        // ds_Query.set("inDtFrom", "20240730");
        // ds_Query.set("inDtTo", "20240730");

    }, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    //필수입력항목 체크
    if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
        $c.gus.cfAlertMsg("거래처를 입력하십시오.");
        ed_clntNo.focus();
        return;
    }

    if ($c.gus.cfIsNull(ed_inDtFrom.getValue()) && $c.gus.cfIsNull(ed_inDtTo.getValue()) && $c.gus.cfIsNull(ed_outDtFrom.getValue()) && $c.gus.cfIsNull(ed_outDtTo.getValue())) {
        $c.gus.cfAlertMsg("입고일자 또는 출고일자를 입력하십시오.");
        ed_clntNo.focus();
        return;
    }


    if (!($c.gus.cfIsNull(ed_inDtFrom.getValue()) || $c.gus.cfIsNull(ed_inDtTo.getValue())) && ($c.gus.cfIsNull(ed_inDtFrom.getValue()) || $c.gus.cfIsNull(ed_inDtTo.getValue()))) {
        $c.gus.cfAlertMsg("입고일자를 입력하십시오.");
        ed_clntNo.focus();
        return;
    }

    if (!($c.gus.cfIsNull(ed_outDtFrom.Text) && $c.gus.cfIsNull(ed_outDtTo.getValue())) && ($c.gus.cfIsNull(ed_outDtFrom.getValue()) || $c.gus.cfIsNull(ed_outDtTo.getValue()))) {
        $c.gus.cfAlertMsg("출고일자를 입력하십시오.");
        ed_clntNo.focus();
        return;
    }

    if (!$c.gus.cfValidate(ed_inDtFrom) || !$c.gus.cfValidate(ed_inDtTo) || !$c.gus.cfValidate(ed_outDtFrom) || !$c.gus.cfValidate(ed_outDtTo)) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_inDtFrom.getValue(), ed_inDtTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_inDtFrom.focus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_outDtFrom.getValue(), ed_outDtTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_outDtFrom.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};

//------------------------------------
// 저장
//------------------------------------
scwin.f_Save = async function () {
    // 필수값 체크
    let ret = await $c.gus.cfValidate([gr_InOutStockInfo])
    if (!ret) return;

    var cnt = 0
    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T" || ds_StockInfo.getRowStatus(i) == "U") {
            if (!$c.gus.cfIsNull(ds_StockInfo.getCellData(i, "invoiceNo"))) {
                $c.win.alert("이미 송장발행된 내역이 있습니다.");
                return;
            }

            if (!$c.gus.cfIsNull(ds_StockInfo.getCellData(i, "outDt")) && ds_StockInfo.getCellData(i, "ioClsCd") == "I") {
                ds_StockInfo.setCellData(i, "ioClsCd", "O");
            }

            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("저장할 항목을 선택해 주세요.");
        return;
    }

    //저장 여부 확인
    ret = await $c.win.confirm(MSG_CM_CRM_001);
    if (ret) { // 저장 하시겠습니까?
        $c.sbm.execute(sbm_save);
    }
}

//------------------------------------
// 삭제
//------------------------------------
scwin.f_Delete = async function () {
    var cnt = 0
    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T") {
            if (!$c.gus.cfIsNull(ds_StockInfo.getCellData(i, "invoiceNo"))) {
                $c.win.alert("송장삭제 후 입출고내역 삭제가능합니다.");
                return;
            }
            //ds_StockInfo.UserStatus(i) = 2;
            ds_StockInfo.modifyRowStatus(i, "D");
            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("삭제할 항목을 선택해 주세요.");
        return;
    }

    let ret = await $c.win.confirm("삭제 하시겠습니까?");
    if (ret) {
        $c.sbm.execute(sbm_save);
    }
}

//------------------------------------
// 수정
//------------------------------------
scwin.f_Update = async function () {
    var cnt = 0
    for (var i = 1; i <= ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T") {
            if (!$c.gus.cfIsNull(ds_StockInfo.getCellData(i, "invoiceNo"))) {
                $c.win.alert("이미 송장발행된 내역이 있습니다.");
                return;
            }
            //ds_StockInfo.UserStatus(i) = 3;
            ds_StockInfo.modifyRowStatus(i, "U");
            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("수정할 항목을 선택해 주세요.");
        return;
    }

    let ret = await $c.win.confirm("수정 하시겠습니까?");
    if (ret) {
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------
// 엑셀 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
    var totCnt = ds_StockInfo.getRowCount();
    var sheetTitle = "포스코입출고 등록";

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                , sheetName: sheetTitle //엑셀내 시트명 지정필요시
            };

            const infoArr = [];

            $c.data.downloadGridViewExcel(gr_InOutStockInfo, options, infoArr);
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.f_outDtUpdate = function () {
    if ($c.gus.cfIsNull(ica_outDt.getValue())) {
        $c.win.alert("출고일자를 선택해주세요.");
        return;
    }

    if (scwin.invoiceChk()) {
        $c.win.alert("송장삭제 후 출고일자 변경 가능합니다");
        return;
    }

    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T") {
            ds_StockInfo.setCellData(i, "outDt", ica_outDt.getValue());
        }

    }
};

scwin.f_outCancelUpdate = function () {
    if (scwin.invoiceChk()) {
        $c.win.alert("송장삭제 후 출고일자 변경 가능합니다");
        return;
    }

    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T") {
            ds_StockInfo.setCellData(i, "outDt", "");
            ds_StockInfo.setCellData(i, "ioClsCd", "I");
        }
    }
};

scwin.invoiceChk = function () {
    var returnChk = false;

    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T" && !$c.gus.cfIsNull(ds_StockInfo.getCellData(i, "invoiceNo"))) {
            return true;
        }
    }

    return returnChk;
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// GRID에서 선택된 오더요청처리 : 해당 오더요청처리 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_srchCond);

    ed_clntNo.focus();
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    var newRow = ds_StockInfo.insertRow();
    ds_StockInfo.setRowPosition(newRow);
    ds_StockInfo.setCellData(ds_StockInfo.getRowPosition(), "ioClsCd", "I");
    ds_StockInfo.setCellData(ds_StockInfo.getRowPosition(), "clntNo", ed_clntNo.getValue());
};

//-------------------------------------------------------------------------
// 송장발행
//-------------------------------------------------------------------------
scwin.f_popup = async function () {
    var arrParam = new Array();
    var arrParam1 = "";
    var arrParam2 = new Array();
    var arrParam3 = new Array();
    var arrParam4 = new Array();
    var arrParam5 = new Array();
    var arrParam6 = "";

    var cnt = 0
    var outDTChk = "";

    if (scwin.invoiceChk()) {
        $c.win.alert("이미 송장발행된 내역이 있습니다.");
        return;
    }

    for (var i = 0; i < ds_StockInfo.getRowCount(); i++) {
        if (ds_StockInfo.getCellData(i, "chk") == "T") {
            if ($c.gus.cfIsNull(ds_StockInfo.getCellData(i, "outDt"))) {
                $c.gus.cfAlertMsg("출고일자 등록 후 송장발행 가능합니다.");
                return;
            }

            if (ds_StockInfo.getCellData(i, "ioClsCd") == "I") {
                $c.gus.cfAlertMsg("출고일자 등록 후 송장발행 가능합니다.");
                return;
            }

            if (outDTChk != "" && outDTChk != ds_StockInfo.getCellData(i, "outDt")) {
                $c.gus.cfAlertMsg("동일한 출고일자로만 송장발행 가능합니다.");
                return;
            }
            cnt++;

            outDTChk = ds_StockInfo.getCellData(i, "outDt");

            arrParam1 = ds_StockInfo.getCellData(i, "outDt");
            arrParam2.push(ds_StockInfo.getCellData(i, "clntNo"));
            arrParam3.push(ds_StockInfo.getCellData(i, "inDt"));
            arrParam4.push(ds_StockInfo.getCellData(i, "productNo"));
            arrParam5.push(ds_StockInfo.getCellData(i, "odrLineNo"));
            arrParam6 = ds_StockInfo.getCellData(i, "transferYn");
        }
    }

    arrParam.push(arrParam1);
    arrParam.push(arrParam2);
    arrParam.push(arrParam3);
    arrParam.push(arrParam4);
    arrParam.push(arrParam5);
    arrParam.push(arrParam6);

    if (cnt == 0) {
        $c.gus.cfAlertMsg("발행 할 항목을 선택해주세요.");
        return;
    }

    let win_url = "/ui/ds/op/wrkrslts/yardwrkrslts/op_302_02_49p.xml";

    let opts = {
        id: "op_302_02_49p",
        popupName: "송장입력",
        modal: true,
        type: "browserPopup",
        width: 500,
        height: 500,
        title: "송장입력"
    };

    var returnParam = await $c.win.openPopup(win_url, opts, arrParam);
    if (returnParam != null) {
        console.log("returnParam[0]=" + returnParam[0])

        var data = {
            reportName: "ds/op/wrkrslts/yardwrkrslts/op_302_02_49.ozr",
            odiParam: {
                clntNo: ed_clntNo.getValue(),
                invoiceNo: returnParam[0] //송장발행으로 생성된 번호 매핑필요
            },
            viewerParam: {
                useprogressbar: true, // 프로그레스바 쓸지 말지
                zoom: 90, // 배율 설정
            },
            formParam: {

            }
        };
        await scwin.openPopup(data);

        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 오즈 리포트 팝업
//------------------------------------------------------------------------- 
scwin.openPopup = async function (data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // 거래처 팝업
            udc_clntNo.setSelectId("retrieveClntInfo2"); // XML상의 SELECT ID
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "계약 거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
    }
};

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_StockInfo.getRowCount() == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
    }

    tbx_totalRows.setValue(ds_StockInfo.getRowCount()); // 소계 부분을 뺀 실제 데이터 갯수를 Count...

    $c.gus.cfEnableObjects([btn_addRow, btn_undoRow, btn_insert, btn_cancel, btn_pop, btn_delete, btn_save]);
};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);

    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 화주 UDC START
//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'F', 'F');
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, ed_clntNm, 1);
};

scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_clntNo, 1, false);
};

scwin.udc_clntNo_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_clntNo, ed_clntNm);
};
//-------------------------------------------------------------------------
// 화주 UDC END
//-------------------------------------------------------------------------
